SELECT user_id, SUM(shares) AS total_shares
FROM investor_stock_relations
GROUP BY user_id;

SELECT SUM(shares) AS total_shares
FROM investor_stock_relations
WHERE user_id = 0;

SELECT AVG(shares) AS average_shares_owned
FROM investor_stock_relations
WHERE symbol_id = (SELECT symbol_id FROM stock_symbols WHERE symbol = 'MHL');

SELECT user_id, shares
FROM investor_stock_relations
WHERE symbol_id = 1;

SELECT date, close
FROM stock_prices
WHERE close = (SELECT MIN(close) FROM stock_prices);
